def is_undulating(number_str):
    digits = [int(c) for c in number_str]
    n = len(digits)
    if n < 2:
        return False
    for i in range(1, n):
        if digits[i] == digits[i-1]:
            return False
        if i % 2 == 1:
            if digits[i] < digits[i-1]:
                return False
        else:
            if digits[i] > digits[i-1]:
                return False
    return True

